class SAMLResponseParser:
    """Parses and validates SAML Response XML."""

    def __init__(self, saml_response_b64):
        self.raw_response = base64.b64decode(saml_response_b64)
        self.xml_string = self.raw_response.decode('utf-8')
        self.root = ET.fromstring(self.xml_string)
        self.errors = []

    def get_status(self):
        """Extract the status code from the SAML response."""
        status_code_elem = self.root.find(
            './/samlp:Status/samlp:StatusCode',
            SAML_NAMESPACES
        )
        if status_code_elem is not None:
            return status_code_elem.get('Value', '')
        return None

    def is_success(self):
        """Check if the SAML response indicates success."""
        status = self.get_status()
        return status == 'urn:oasis:names:tc:SAML:2.0:status:Success'

    def get_assertion(self):
        """Extract the Assertion element from the response."""
        assertion = self.root.find('.//saml:Assertion', SAML_NAMESPACES)
        return assertion

    def validate_assertion_present(self):
        """Validate that an assertion is present in the response."""
        assertion = self.get_assertion()
        if assertion is None:
            self.errors.append('No SAML Assertion found in the response.')
            return False
        return True

    def validate_conditions(self):
        """Validate the Conditions element (time-based and audience)."""
        assertion = self.get_assertion()
        if assertion is None:
            self.errors.append('Cannot validate conditions: no assertion found.')
            return False

        conditions = assertion.find('saml:Conditions', SAML_NAMESPACES)
        if conditions is None:
            self.errors.append('No Conditions element found in assertion.')
            return False

        now = datetime.utcnow()

        not_before = conditions.get('NotBefore')
        if not_before:
            not_before_dt = datetime.strptime(not_before, '%Y-%m-%dT%H:%M:%SZ')
            # Allow 5 minutes clock skew
            if now < not_before_dt - timedelta(minutes=5):
                self.errors.append(
                    f'Assertion not yet valid. NotBefore: {not_before}, Now: {now.isoformat()}'
                )
                return False

        not_on_or_after = conditions.get('NotOnOrAfter')
        if not_on_or_after:
            not_on_or_after_dt = datetime.strptime(not_on_or_after, '%Y-%m-%dT%H:%M:%SZ')
            # Allow 5 minutes clock skew
            if now >= not_on_or_after_dt + timedelta(minutes=5):
                self.errors.append(
                    f'Assertion has expired. NotOnOrAfter: {not_on_or_after}, Now: {now.isoformat()}'
                )
                return False

        # Validate audience restriction
        audience_restriction = conditions.find(
            'saml:AudienceRestriction/saml:Audience',
            SAML_NAMESPACES
        )
        if audience_restriction is not None:
            audience = audience_restriction.text
            if audience != SAML_CONFIG['sp_entity_id']:
                self.errors.append(
                    f'Audience mismatch. Expected: {SAML_CONFIG["sp_entity_id"]}, Got: {audience}'
                )
                return False

        return True

    def validate_destination(self):
        """Validate the Destination attribute of the response."""
        destination = self.root.get('Destination', '')
        if destination and destination != SAML_CONFIG['sp_acs_url']:
            self.errors.append(
                f'Destination mismatch. Expected: {SAML_CONFIG["sp_acs_url"]}, Got: {destination}'
            )
            return False
        return True

    def validate_issuer(self):
        """Validate the Issuer of the response and assertion."""
        # Check response-level issuer
        response_issuer = self.root.find('saml:Issuer', SAML_NAMESPACES)
        if response_issuer is not None:
            if response_issuer.text != SAML_CONFIG['idp_entity_id']:
                self.errors.append(
                    f'Response Issuer mismatch. Expected: {SAML_CONFIG["idp_entity_id"]}, '
                    f'Got: {response_issuer.text}'
                )
                return False

        # Check assertion-level issuer
        assertion = self.get_assertion()
        if assertion is not None:
            assertion_issuer = assertion.find('saml:Issuer', SAML_NAMESPACES)
            if assertion_issuer is not None:
                if assertion_issuer.text != SAML_CONFIG['idp_entity_id']:
                    self.errors.append(
                        f'Assertion Issuer mismatch. Expected: {SAML_CONFIG["idp_entity_id"]}, '
                        f'Got: {assertion_issuer.text}'
                    )
                    return False

        return True

    def validate_in_response_to(self, expected_request_id=None):
        """Validate InResponseTo attribute if we track request IDs."""
        if expected_request_id:
            in_response_to = self.root.get('InResponseTo', '')
            if in_response_to != expected_request_id:
                self.errors.append(
                    f'InResponseTo mismatch. Expected: {expected_request_id}, Got: {in_response_to}'
                )
                return False
        return True

    def validate(self, expected_request_id=None):
        """Run all validations."""
        results = [
            self.validate_assertion_present(),
            self.validate_destination(),
            self.validate_issuer(),
            self.validate_conditions(),
            self.validate_in_response_to(expected_request_id),
        ]
        if not self.is_success():
            self.errors.append(f'SAML Response status is not Success: {self.get_status()}')
            return False
        return all(results)

    def get_name_id(self):
        """Extract the NameID from the assertion's Subject."""
        assertion = self.get_assertion()
        if assertion is None:
            return None

        name_id = assertion.find(
            'saml:Subject/saml:NameID',
            SAML_NAMESPACES
        )
        if name_id is not None:
            return {
                'value': name_id.text,
                'format': name_id.get('Format', ''),
                'sp_name_qualifier': name_id.get('SPNameQualifier', ''),
                'name_qualifier': name_id.get('NameQualifier', ''),
            }
        return None

    def get_session_index(self):
        """Extract the SessionIndex from AuthnStatement."""
        assertion = self.get_assertion()
        if assertion is None:
            return None

        authn_statement = assertion.find('saml:AuthnStatement', SAML_NAMESPACES)
        if authn_statement is not None:
            return authn_statement.get('SessionIndex', '')
        return None

    def get_attributes(self):
        """Extract user attributes from the assertion's AttributeStatement."""
        assertion = self.get_assertion()
        if assertion is None:
            return {}

        attributes = {}
        attr_statement = assertion.find('saml:AttributeStatement', SAML_NAMESPACES)

        if attr_statement is None:
            return attributes

        for attr in attr_statement.findall('saml:Attribute', SAML_NAMESPACES):
            attr_name = attr.get('Name', '')
            friendly_name = attr.get('FriendlyName', '')

            values = []
            for attr_value in attr.findall('saml:AttributeValue', SAML_NAMESPACES):
                if attr_value.text:
                    values.append(attr_value.text)

            # Use friendly name as key if available, otherwise use full name
            key = friendly_name if friendly_name else attr_name

            if len(values) == 1:
                attributes[key] = values[0]
            elif len(values) > 1:
                attributes[key] = values
            else:
                attributes[key] = None

        return attributes

    def get_user_data(self):
        """Get all parsed user data from the SAML assertion."""
        return {
            'name_id': self.get_name_id(),
            'session_index': self.get_session_index(),
            'attributes': self.get_attributes(),
        }


def create_authn_request():
    """Create a SAML AuthnRequest XML."""
    request_id = f'_id-{uuid.uuid4().hex}'
    issue_instant = datetime.utcnow().strftime('%Y-%m-%dT%H:%M:%SZ')

    authn_request = f'''<samlp:AuthnRequest
        xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol"
        xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
        ID="{request_id}"
        Version="2.0"
        IssueInstant="{issue_instant}"
        Destination="{SAML_CONFIG['idp_sso_url']}"
        AssertionConsumerServiceURL="{SAML_CONFIG['sp_acs_url']}"
        ProtocolBinding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST">
        <saml:Issuer>{SAML_CONFIG['sp_entity_id']}</saml:Issuer>
        <samlp:NameIDPolicy
            Format="urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress"
            AllowCreate="true"/>
    </samlp:AuthnRequest>'''

    return request_id, authn_request


def create_logout_request(name_id, session_index):
    """Create a SAML LogoutRequest XML."""
    request_id = f'_id-{uuid.uuid4().hex}'
    issue_instant = datetime.utcnow().strftime('%Y-%m-%dT%H:%M:%SZ')

    logout_request = f'''<samlp:LogoutRequest
        xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol"
        xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
        ID="{request_id}"
        Version="2.0"
        IssueInstant="{issue_instant}"
        Destination="{SAML_CONFIG['idp_slo_url']}">
        <saml:Issuer>{SAML_CONFIG['sp_entity_id']}</saml:Issuer>
        <saml:NameID Format="urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress">
            {name_id}
        </saml:NameID>
        <samlp:SessionIndex>{session_index}</samlp:SessionIndex>
    </samlp:LogoutRequest>'''

    return request_id, logout_request


def login_required(f):
    """Decorator to require SAML authentication."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'user' not in session:
            session['relay_state'] = request.url
            return redirect(url_for('saml_login'))
        return f(*args, **kwargs)
    return decorated_function


